#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e5+10,M=6e5+10;int head[N],des[M],nxt[M],cgt=1;
int n,m,deg[N],stk[M],ans[M],tot,top;bool vis[M],jud[M],res[M];
inline void ins(int x,int y)
{
	nxt[++cgt]=head[x];des[head[x]=cgt]=y;++deg[y];
	nxt[++cgt]=head[y];des[head[y]=cgt]=x;++deg[x];
}
inline void dfs(int u)
{
	for(int &i=head[u];i;i=nxt[i])if(!jud[i>>1])
		{int v=des[i];stk[++top]=i;jud[i>>1]=true;dfs(v);}
	ans[++tot]=stk[top--];
}
int main()
{
	n=read();m=read();rep(1,m,i)ins(read(),read());
	int lst=0;rep(1,n,i)if(deg[i]&1){if(lst)ins(lst,i),lst=0;else lst=i;}
	if(cgt>>1&1)ins(1,1);rep(1,n,i)if(!vis[i])top=0,dfs(i);
	rep(1,tot,i){int u=ans[i];res[u>>1]=(u&1)==(i&1);}
	printf("%d\n",cgt>>1);
	rep(1,cgt>>1,i)
	{
		int u=des[i<<1],v=des[i<<1|1];
		if(res[i])swap(u,v);printf("%d %d\n",u,v);
	}
}
